'use client'
import Link from 'next/link';
import "../globals.css"; 
import React,{FC, useState, useEffect} from 'react';
import NavItems from "../utils/NavItems.tsx";

type Props = {
    open: boolean;
    setOpen: (open: boolean) => void;
    activeItem: number;
}

const Header:FC<Props> = (props) => {
    const [openSidebar, setOpenSidebar] = useState(false);
    const [active, setActive] = useState(false);

      useEffect(() => {
        const handleScroll = () => {
            if (window.scrollY > 80) {
                setActive(true);
            } else {
                setActive(false);
            }
        };

        window.addEventListener("scroll", handleScroll);

        return () => {
            window.removeEventListener("scroll", handleScroll);
        };
    }, []);

  return (
    <div className='w-full relative '>
            <div className={`${
            active 
            ? "dark:bg-opacity-50 dark:bg-linear-to-b dark:from-gray-900 dark:to-black fixed top-0 left-0 w-full h-20 z-80 border-b dark:border-[#ffffff1c] shadow-xl transition duration-500"
            : "w-full border-b dark:border-[#ffffff1c] h-20 z-80 dark:shadow"
            }`}>
                <div className="w-[95%] m-auto py-2 h-full ">
                     <div className="w-full h-20 flex items-center justify-between p-3">
                         <div>
                            <Link  href={"/"} 
                            className={`text-[25px] font-Poppins font-medium text-black dark:text-white` } 
                            >
                                ZyLO Learning
                               </Link>
                         </div>
                         <div className="flex item-center">
                             <NavItems 
                              activeItem={activeItem} 
                              isMobile={false}
                              />
                         </div>
                     </div>
                </div>
            </div>
    </div>
  );
};

export default Header;